{
  "level": "B2",
  "intro": "W tym temacie poznasz <strong>Future Perfect Passive</strong> i zobaczysz, jak mówić o rezultacie ukończonym przed konkretnym terminem w przyszłości.",
  "rules": [
    {
      "label": "Wzór",
      "color": "emerald",
      "text": "<strong>subject + will have been + V3</strong>:",
      "example": "The project will have been completed by Friday."
    },
    {
      "label": "Przeczenie",
      "color": "rose",
      "text": "<strong>subject + will not have been + V3</strong>:",
      "example": "The report will not have been submitted by then."
    },
    {
      "label": "Pytanie",
      "color": "blue",
      "text": "<strong>Will + subject + have been + V3?</strong>:",
      "example": "Will the work have been finished by Monday?"
    }
  ]
}

{
  "title": "1. Budowa Future Perfect Passive",
  "intro": "<strong>Will have been</strong> jest takie samo dla wszystkich osób:",
  "items": [
    {
      "label": "Wszystkie osoby",
      "title": "will have been + V3",
      "subtitle": "All the documents will have been signed by tomorrow."
    },
    {
      "label": "Liczba pojedyncza",
      "title": "will have been + V3",
      "subtitle": "The report will have been submitted by noon."
    },
    {
      "label": "Liczba mnoga",
      "title": "will have been + V3",
      "subtitle": "All the tasks will have been completed by Monday."
    },
    {
      "label": "Uwaga",
      "title": "have been jest stałe",
      "subtitle": "W tej konstrukcji po <strong>will</strong> zawsze stoi <strong>have been</strong>."
    }
  ]
}

{
    "title": "2. Zdania twierdzące",
    "sections": [
        {
            "label": "Struktura",
            "color": "emerald",
            "description": "Kolejność słów: <strong>podmiot + będzie + V3 (+ przez agenta)</strong>",
            "examples": [
                {
                    "en": "The project will have been completed by Friday.",
                    "ua": "Projekt zakończy się w piątek."
                },
                {
                    "en": "All the documents will have been signed by tomorrow.",
                    "ua": "Wszystkie dokumenty zostaną podpisane jutro."
                },
                {
                    "en": "The work will have been finished by the end of the week.",
                    "ua": "Prace zakończą się do końca tygodnia."
                },
                {
                    "en": "The emails will have been sent by 6 PM.",
                    "ua": "Listy będą wysyłane do godziny 18:00."
                }
            ]
        },
        {
            "label": "Do pewnego momentu",
            "color": "sky",
            "description": "Podkreślamy, że akcja <strong>zostanie zakończona w określonym czasie</strong>:",
            "examples": [
                {
                    "en": "By next month, the building will have been renovated.",
                    "ua": "Budynek zostanie naprawiony w przyszłym miesiącu."
                },
                {
                    "en": "By 2030, many changes will have been made.",
                    "ua": "Do 2030 roku nastąpi wiele zmian."
                },
                {
                    "en": "By the time you arrive, dinner will have been prepared.",
                    "ua": "Kolacja będzie gotowa, kiedy przyjedziesz."
                }
            ]
        }
    ]
}

{
    "title": "3. Kiedy używać opcji pasywnej Future Perfect?",
    "sections": [
        {
            "label": "Ukończenie do punktu w przyszłości",
            "color": "emerald",
            "description": "Kiedy ważne jest, aby działanie <strong>zakończyło się w określonym czasie</strong>:",
            "examples": [
                {
                    "en": "The contract will have been signed by Monday.",
                    "ua": "Umowa zostanie podpisana w poniedziałek."
                },
                {
                    "en": "The repairs will have been done by next week.",
                    "ua": "Naprawa zakończy się w przyszłym tygodniu."
                },
                {
                    "en": "The order will have been delivered by noon.",
                    "ua": "Zamówienie zostanie dostarczone do południa."
                }
            ]
        },
        {
            "label": "Terminy i terminy",
            "color": "blue",
            "description": "Aby opisać <strong>ukończenie w terminie</strong>:",
            "examples": [
                {
                    "en": "The report will have been submitted before the deadline.",
                    "ua": "Sprawozdanie zostanie złożone w terminie."
                },
                {
                    "en": "All tests will have been completed by June.",
                    "ua": "Wszystkie testy zakończą się do czerwca."
                },
                {
                    "en": "The budget will have been approved by the end of the quarter.",
                    "ua": "Budżet zostanie zatwierdzony do końca kwartału."
                }
            ]
        },
        {
            "label": "Prognozy na przyszłość",
            "color": "amber",
            "description": "Aby zakończyć <strong>prognozy</strong>:",
            "examples": [
                {
                    "en": "By 2050, many problems will have been solved.",
                    "ua": "Do roku 2050 wiele problemów zostanie rozwiązanych."
                },
                {
                    "en": "The new system will have been implemented by then.",
                    "ua": "Do tego czasu nowy system zostanie wdrożony."
                },
                {
                    "en": "A cure will have been found by the end of the decade.",
                    "ua": "Pod koniec dekady zostanie wynalezione lekarstwo."
                }
            ]
        }
    ]
}

{
    "title": "4. Zdania przeczące",
    "sections": [
        {
            "label": "Struktura",
            "color": "rose",
            "description": "Dodaj <strong>nie</strong> po will: <strong>podmiot + nie będzie + V3</strong>",
            "examples": [
                {
                    "en": "The project will not have been finished by Friday.",
                    "ua": "Projekt zakończy się dopiero w piątek."
                },
                {
                    "en": "The documents will not have been signed by then.",
                    "ua": "Do tego czasu dokumenty nie zostaną podpisane."
                },
                {
                    "en": "The report will not have been submitted before the deadline.",
                    "ua": "Sprawozdanie nie zostanie złożone przed upływem terminu."
                },
                {
                    "en": "All tasks will not have been completed by Monday.",
                    "ua": "Nie wszystkie zadania uda się zrealizować do poniedziałku."
                }
            ]
        },
        {
            "label": "Skrócona forma",
            "color": "amber",
            "description": "Potocznie: <strong>nie będzie</strong>",
            "examples": [
                {
                    "en": "The work won't have been finished by tomorrow.",
                    "ua": "Prace zakończą się dopiero jutro."
                },
                {
                    "en": "The email won't have been sent by 5 PM.",
                    "ua": "List zostanie wysłany dopiero o godzinie 17:00."
                },
                {
                    "en": "The decision won't have been made by then.",
                    "ua": "Do tego czasu nie zostanie podjęta żadna decyzja."
                }
            ]
        }
    ]
}

{
    "title": "5. Zdania pytające",
    "sections": [
        {
            "label": "Pytania yes/no",
            "color": "blue",
            "description": "<strong>Czy + podmiot + były + V3?</strong>",
            "examples": [
                {
                    "en": "Will the project have been completed by Friday?",
                    "ua": "Czy projekt zakończy się do piątku?"
                },
                {
                    "en": "Will all documents have been signed by tomorrow?",
                    "ua": "Czy do jutra wszystkie dokumenty zostaną podpisane?"
                },
                {
                    "en": "Will the work have been finished by then?",
                    "ua": "Czy do tego czasu prace zostaną ukończone?"
                },
                {
                    "en": "Will the order have been delivered by noon?",
                    "ua": "Czy zamówienie zostanie dostarczone do południa?"
                }
            ]
        },
        {
            "label": "Jakie pytanie",
            "color": "sky",
            "description": "<strong>Wh-word + będzie + podmiot + było + V3?</strong>",
            "examples": [
                {
                    "en": "What will have been done by Friday?",
                    "ua": "Co zostanie zrobione do piątku?"
                },
                {
                    "en": "How much will have been completed by the deadline?",
                    "ua": "Ile z nich uda się ukończyć w wyznaczonym terminie?"
                },
                {
                    "en": "When will the report have been submitted?",
                    "ua": "Kiedy raport zostanie złożony?"
                },
                {
                    "en": "Why will the project have been delayed?",
                    "ua": "Dlaczego projekt będzie opóźniony?"
                }
            ]
        },
        {
            "label": "Krótkie odpowiedzi",
            "color": "amber",
            "description": "Odpowiedzi zawierające <strong>Tak/Nie + zaimek + will (not) have</strong>:",
            "examples": [
                {
                    "en": "Will the email have been sent? — Yes, it will. / No, it won't.",
                    "ua": "Czy list zostanie wysłany? - Tak. / NIE."
                },
                {
                    "en": "Will they have been informed? — Yes, they will. / No, they won't.",
                    "ua": "Czy zostaną poinformowani? - Tak. / NIE."
                }
            ]
        }
    ]
}

{
    "title": "6. Porównanie czasu aktywnego i pasywnego w czasie Future Perfect",
    "intro": "Jak zamienić zdanie czynne w stronę bierną:",
    "rows": [
        {
            "en": "Active: They will have completed the project.",
            "ua": "Zrealizują projekt.",
            "note": "→ Passive: The project will have been completed."
        },
        {
            "en": "Active: Someone will have sent the email.",
            "ua": "Ktoś wyśle ​​list.",
            "note": "→ Passive: The email will have been sent."
        },
        {
            "en": "Active: The company will have hired new staff.",
            "ua": "Firma zatrudni nowych pracowników.",
            "note": "→ Passive: New staff will have been hired."
        },
        {
            "en": "Active: We will have made a decision.",
            "ua": "Podejmiemy decyzję.",
            "note": "→ Passive: A decision will have been made."
        }
    ],
    "warning": "📌 Oznaczenia czasu (do piątku, do końca) pozostają!"
}

{
    "title": "7. Porównanie przyszłych form biernych",
    "intro": "Tak wygląda różnica między trzema ważnymi formami przyszłości w stronie biernej:",
    "rows": [
        {
            "en": "Future Simple: The letter will be sent tomorrow.",
            "ua": "List zostanie wysłany jutro.",
            "note": "→ zwykłe mówienie o przyszłości"
        },
        {
            "en": "Future Continuous: The letter will be being written. (rare)",
            "ua": "Ta forma jest poprawna, ale bardzo rzadka.",
            "note": "→ proces w określonym momencie przyszłości"
        },
        {
            "en": "Future Perfect: The letter will have been sent by 5 PM.",
            "ua": "List zostanie wysłany do 17:00.",
            "note": "→ czynność będzie ukończona do konkretnego momentu"
        }
    ],
    "warning": "📌 <strong>Future Perfect Passive</strong> podkreśla ukończenie przed wskazanym momentem."
}

{
    "title": "8. Markery czasu dla Future Perfect Passive",
    "intro": "Najczęściej spotkasz tu wyrażenia wskazujące na <strong>termin graniczny</strong>:",
    "items": [
        {
            "label": "By + time",
            "title": "by Friday, by 5 PM, by tomorrow",
            "subtitle": "The report will have been submitted by Friday."
        },
        {
            "label": "By the end of",
            "title": "by the end of + period",
            "subtitle": "The project will have been completed by the end of the month."
        },
        {
            "label": "By then",
            "title": "by then",
            "subtitle": "By then, all tasks will have been finished."
        },
        {
            "label": "By + year",
            "title": "by 2030, by next year",
            "subtitle": "By 2030, many changes will have been made."
        }
    ]
}

{
    "title": "9. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Brak been.",
            "wrong": "The report will have completed.",
            "right": "✅ The report will have been completed."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Mylenie being i been.",
            "wrong": "The work will have being done.",
            "right": "✅ The work will have been done."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Nieprawidłowy szyk.",
            "wrong": "The letter will been have sent.",
            "right": "✅ The letter will have been sent."
        },
        {
            "label": "Błąd 4",
            "color": "rose",
            "title": "Future Simple zamiast Future Perfect.",
            "wrong": "The project will be finished by Friday. (gdy ważne jest ukończenie przed terminem)",
            "right": "✅ The project will have been finished by Friday."
        }
    ]
}
